(() => {
    type FieldFor<T> = T extends string
      ? {kind: 'text'; value: string}
      : T extends number
        ? {kind: 'number'; value: number; min?: number}
        : T extends boolean
          ? {kind: 'checkbox'; value: boolean}
          : never;
    interface User {
      name: string;
      age: number;
      admin: boolean;
    }
    type UserForm = {[K in keyof User]: FieldFor<User[K]>};
    return {build: () => createValidate<UserForm>(), buildErrors: () => noErrs(createGetValidationErrors<UserForm>())};
  })()

() =>
    createValidate(
      RT.object({
        name: RT.object({kind: RT.literal('text'), value: RT.string()}),
        age: RT.object({kind: RT.literal('number'), value: RT.number(), min: RT.optional(RT.number())}),
        admin: RT.object({kind: RT.literal('checkbox'), value: RT.boolean()}),
      })
    )

(() => {
    type FieldFor<T> = T extends string
      ? {kind: 'text'; value: string}
      : T extends number
        ? {kind: 'number'; value: number; min?: number}
        : T extends boolean
          ? {kind: 'checkbox'; value: boolean}
          : never;
    interface User {
      name: string;
      age: number;
      admin: boolean;
    }
    type UserForm = {[K in keyof User]: FieldFor<User[K]>};
    return {
      build: () => {
        const check = typia.createIs<UserForm>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<UserForm>();
        return (v) => val(v).success;
      },
    };
  })()

